module multi_pipe_4bit #(
    parameter size = 4
) (
    input clk,
    input rst_n,
    input [size-1:0] mul_a,
    input [size-1:0] mul_b,
    output reg [2*size-1:0] mul_out
);

    wire [size-1:0] a_ext = {mul_a[size-1], mul_a[size-1:0]};
    wire [size-1:0] b_ext = {mul_b[size-1], mul_b[size-1:0]};

    reg [size-1:0] partial_products [size-1:0];
    reg [2*size-1:0] sum_registers [size-1:0];

    genvar i;
    generate
        for (i = 0; i < size; i = i + 1) begin
            always @(*) begin
                if (b_ext[i])
                    partial_products[i] = a_ext << i;
                else
                    partial_products[i] = 'd0;
            end
        end
    endgenerate

    integer j;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            for (j = 0; j < size; j = j + 1)
                sum_registers[j] <= 'd0;
        end
        else begin
            sum_registers[0] <= partial_products[0];
            for (j = 1; j < size; j = j + 1)
                sum_registers[j] <= sum_registers[j-1] + partial_products[j];
        end
    end

    always @(posedge clk or negedge rst_n) begin
        if (!rst_n)
            mul_out <= 'd0;
        else
            mul_out <= sum_registers[size-1];
    end

endmodule
